{
  "description": "This quiz assesses knowledge of HTML5 semantic elements, testing the ability to distinguish and correctly use tags beyond basic <div> and <span>. It is moderately challenging, presented with a light‑hearted, encouraging tone that nudges learners toward better markup practices. The quiz aims to gauge both foundational HTML understanding and readiness to apply semantic best‑practices in real projects.",
  "topics": [
    "HTML5 semantic tags (header, nav, article, section, footer, etc.)",
    "Proper use of structural elements versus generic containers",
    "Accessibility considerations in markup",
    "Differences between block‑level and inline elements"
  ],
  "audience": "Front‑end developers, web designers, and students who already know basic HTML and want to validate or improve their semantic HTML5 skills."
}
